      row.push(cell);
      rows.push(row);
      row = [];
      cell = '';
      index += 1;
      continue;
    }

    cell += char;
    index += 1;
  }

  row.push(cell);
  if (row.length > 1 || compact(row[0])) {
    rows.push(row);
  }

  return rows;
};

